#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e4 + 5;

int n, m;
char maze[MAXN][MAXN];
int tot;
int vis[MAXN][MAXN], ans[1000005];

int dx[4] = {0, 1, 0, -1};
int dy[4] = {1, 0, -1, 0};

bool inmap(int x, int y)
{
	return 0 < x && x <= n && 0 < y && y <= n;
}

void dfs(int x, int y, int col)
{
	vis[x][y] = col;
	ans[col]++;
	for (int i = 0; i < 4; i++)
	{
		int nx = x + dx[i], ny = y + dy[i];
		if (!inmap(nx, ny))continue;
		if (maze[nx][ny] == maze[x][y])continue;
		if (vis[nx][ny] != 0)continue;
		dfs(nx, ny, col);
	}
}

signed main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= n; i++)
	{
		cin >> (maze[i] + 1);
	}
	for (int i = 1; i <= n; i++)
	{
		for (int j = 1; j <= n; j++)
		{
			if (vis[i][j] == 0)
			{
				dfs(i, j, ++tot);
			}
		}
	}
	while (m--)
	{
		int u, v;
		cin >> u >> v;
		cout << ans[vis[u][v]] << endl;
	}
	return false;
}
